/* Estilos del componente de login | Login component styles */
/* Autor: Camilo Martinez | Fecha: 15/04/2026 */
/* Estética: Crema/Dorado con transparencia y bordes redondeados */

/* Variables de color | Color variables */
:host {
  --color-oro: #d4af37;
  --color-oro-claro: #f4e5b7;
  --color-crema: #fff8e7;
  --color-crema-oscuro: #f0e6c8;
  --color-texto: #2c2c2c;
  --color-texto-suave: #666;
  --color-borde: rgba(212, 175, 55, 0.3);
  --sombra-suave: 0 8px 32px rgba(212, 175, 55, 0.15);
  --radio-borde: 20px;
}

/* Wrapper principal | Main wrapper */
.login-wrapper {
  background: linear-gradient(135deg, var(--color-crema) 0%, var(--color-oro-claro) 100%);
  min-height: 100vh;
  padding: 20px;
}

/* Tarjeta de login con efecto glassmorphism | Login card with glassmorphism effect */
.login-card {
  width: 100%;
  max-width: 420px;
  background: rgba(255, 255, 255, 0.85);
  backdrop-filter: blur(10px);
  -webkit-backdrop-filter: blur(10px);
  border-radius: var(--radio-borde);
  border: 1px solid rgba(255, 255, 255, 0.5);
  box-shadow: var(--sombra-suave);
  overflow: hidden;
  transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.login-card:hover {
  transform: translateY(-5px);
  box-shadow: 0 12px 40px rgba(212, 175, 55, 0.2);
}

/* Encabezado dorado | Gold header */
.login-header {
  background: linear-gradient(135deg, var(--color-oro) 0%, #b8922c 100%);
  color: white;
  position: relative;
  overflow: hidden;
}

.login-header::before {
  content: '';
  position: absolute;
  top: -50%;
  left: -50%;
  width: 200%;
  height: 200%;
  background: radial-gradient(circle, rgba(255,255,255,0.1) 0%, transparent 70%);
  animation: shimmer 3s infinite;
}

@keyframes shimmer {
  0%, 100% { transform: translate(-30%, -30%); }
  50% { transform: translate(30%, 30%); }
}

.login-header h2 {
  font-weight: 700;
  font-size: 1.75rem;
  text-shadow: 0 2px 4px rgba(0,0,0,0.2);
  position: relative;
  z-index: 1;
}

.login-header p {
  font-size: 0.9rem;
  opacity: 0.9;
  position: relative;
  z-index: 1;
}

.logo-icon {
  font-size: 3rem;
  filter: drop-shadow(0 2px 4px rgba(0,0,0,0.2));
}

/* Cuerpo del formulario | Form body */
.login-body {
  padding: 32px;
}

/* Alerta de error | Error alert */
.alert-error {
  background: rgba(220, 53, 69, 0.1);
  border: 1px solid rgba(220, 53, 69, 0.3);
  border-radius: 12px;
  padding: 12px 16px;
  color: #dc3545;
  font-size: 0.9rem;
  margin-bottom: 20px;
}

.error-icon {
  font-size: 1.2rem;
}

/* Grupos de formulario | Form groups */
.form-label {
  font-weight: 600;
  color: var(--color-texto);
  font-size: 0.9rem;
  margin-bottom: 8px;
  display: flex;
  align-items: center;
  gap: 6px;
}

.label-icon {
  font-size: 1rem;
}

/* Inputs estilizados | Styled inputs */
.form-control {
  width: 100%;
  padding: 14px 16px;
  border: 2px solid var(--color-borde);
  border-radius: 12px;
  font-size: 1rem;
  background: rgba(255, 255, 255, 0.9);
  transition: all 0.3s ease;
}

.form-control:focus {
  outline: none;
  border-color: var(--color-oro);
  box-shadow: 0 0 0 4px rgba(212, 175, 55, 0.15);
  background: white;
}

.form-control::placeholder {
  color: #aaa;
}

.form-control.is-invalid {
  border-color: #dc3545;
}

.form-control.is-invalid:focus {
  box-shadow: 0 0 0 4px rgba(220, 53, 69, 0.15);
}

/* Feedback de validación | Validation feedback */
.invalid-feedback {
  font-size: 0.8rem;
  color: #dc3545;
  margin-top: 6px;
  padding: 4px 8px;
  background: rgba(220, 53, 69, 0.1);
  border-radius: 6px;
}

/* Botón de submit | Submit button */
.btn-submit {
  background: linear-gradient(135deg, var(--color-oro) 0%, #b8922c 100%);
  color: white;
  border: none;
  border-radius: 12px;
  font-size: 1rem;
  cursor: pointer;
  transition: all 0.3s ease;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.btn-submit:hover:not(:disabled) {
  background: linear-gradient(135deg, #e5c14a 0%, #c9a53a 100%);
  transform: translateY(-2px);
  box-shadow: 0 6px 20px rgba(212, 175, 55, 0.4);
}

.btn-submit:disabled {
  opacity: 0.7;
  cursor: not-allowed;
}

/* Link dorado | Gold link */
.link-gold {
  color: var(--color-oro);
  text-decoration: none;
  transition: all 0.2s ease;
}

.link-gold:hover {
  color: #b8922c;
  text-decoration: underline;
}

/* Spinner de carga | Loading spinner */
.spinner-border {
  width: 1rem;
  height: 1rem;
  border-width: 0.15em;
}

/* Responsive */
@media (max-width: 480px) {
  .login-card {
    max-width: 100%;
    border-radius: 16px;
  }

  .login-body {
    padding: 24px;
  }

  .login-header h2 {
    font-size: 1.5rem;
  }

  .logo-icon {
    font-size: 2.5rem;
  }
}
